// Script Include
var UserUtilsAjax = Class.create();
UserUtilsAjax.prototype = Object.extendsObject(AbstractAjaxProcessor, {
  getDepartment: function() {
    var userId = this.getParameter('sysparm_user_id');
    if (!userId) {
      return '';
    }

    var userGr = new GlideRecord('sys_user');
    if (userGr.get(userId)) {
      return userGr.getDisplayValue('department');
    }
    return '';
  },

  type: 'UserUtilsAjax'
});

// Client Script usage
var ga = new GlideAjax('UserUtilsAjax');
ga.addParam('sysparm_name', 'getDepartment');
ga.addParam('sysparm_user_id', g_form.getValue('requested_for'));
ga.getXMLAnswer(function(answer) {
  g_form.showFieldMsg('requested_for', 'Department: ' + answer, 'info');
});
